(function(){"use strict";const OA=window.OrbArena;class ContentValidationSystem{static validate(){const errors=[],warnings=[],ids=new Set();for(const c of OA.CharacterRegistry.all()){if(ids.has(c.id))errors.push(`ID duplicado: ${c.id}`);ids.add(c.id);for(const key of ["id","name","class","rarity","kit"])if(!c[key])errors.push(`${c.id||"?"}: ${key} ausente`);for(const key of ["active","passive","reactive","ultimate"])if(!c.kit?.[key])errors.push(`${c.id}: kit ${key} ausente`);if(!OA.CHARACTER_RARITIES[c.rarity])errors.push(`${c.id}: raridade desconhecida`);if(!c.tags.length)errors.push(`${c.id}: tags ausentes`);for(const [key,value] of Object.entries(c.stats))if(typeof value==="number"&&(!Number.isFinite(value)||value<0))errors.push(`${c.id}: stat ${key} inválido`);if(c.powerId&&!OA.PowerRegistry.get(c.powerId))errors.push(`${c.id}: poder ${c.powerId} inexistente`);if(!OA.CharacterMechanics.get(c.mechanic))errors.push(`${c.id}: mecânica sem handler`);}for(const p of OA.PowerRegistry.all()){if(p.cooldown<OA.CHARACTER_LIMITS.maxCooldownFloor)errors.push(`${p.id}: cooldown inválido`);if(typeof p.activate!=="function")errors.push(`${p.id}: activate ausente`);if(!p.tags.length)errors.push(`${p.id}: tags ausentes`);}const budgets=new OA.CharacterBalanceSystem().audit;for(const row of budgets)if(row.review)warnings.push(`${row.id}: budget ${row.delta>0?"+":""}${row.delta}%`);return{valid:errors.length===0,errors,warnings,characters:OA.CharacterRegistry.all().length,powers:OA.PowerRegistry.all().length};}}OA.ContentValidationSystem=ContentValidationSystem;}());
